class LmdbUnionFilterValuesBindingIT {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final String MEDICAL = "http://example.com/theme/medical/";
	private static final IRI CONDITION = VF.createIRI(MEDICAL, "Condition");
	private static final IRI MEDICATION = VF.createIRI(MEDICAL, "Medication");
	private static final IRI CODE = VF.createIRI(MEDICAL, "code");

	@Test
	void unionFilterKeepsValuesBindingWhenFilterUsesBranchBinding(@TempDir File dataDir) throws Exception {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig());
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadMedicalCodeData(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();

			String query = String.join("\n",
					"PREFIX med: <http://example.com/theme/medical/>",
					"SELECT (COUNT(DISTINCT ?entity) AS ?count) WHERE {",
					"  VALUES ?target { \"DX-200\" \"DX-201\" }",
					"  { ?entity a med:Condition ; med:code ?code . }",
					"  UNION",
					"  { ?entity a med:Medication ; med:code ?code . }",
					"  FILTER(?code = ?target || ?code = \"DX-202\")",
					"  OPTIONAL { ?entity med:code ?alt . }",
					"}");

			assertEquals(1L, evaluateCount(repository, query),
					"VALUES-bound ?target must remain visible when the UNION branch binds ?code");
		} finally {
			repository.shutDown();
		}
	}

	@Test
	void medicalRecordsQueryOneKeepsValuesBindingInThemeData(@TempDir File dataDir) throws Exception {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig());
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadThemeData(repository, Theme.MEDICAL_RECORDS);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();

			String query = ThemeQueryCatalog.queryFor(Theme.MEDICAL_RECORDS, 1);
			long expectedCount = ThemeQueryCatalog.expectedCountBindingValueFor(Theme.MEDICAL_RECORDS, 1)
					.orElseThrow();
			long actualCount = evaluateCount(repository, query);

			assertEquals(expectedCount, actualCount,
					"MEDICAL_RECORDS q1 count binding must match the catalog expectation");
		} finally {
			repository.shutDown();
		}
	}

	private static void loadMedicalCodeData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);

			Resource condition = VF.createIRI("urn:test:condition:1");
			connection.add(condition, RDF.TYPE, CONDITION);
			connection.add(condition, CODE, VF.createLiteral("DX-200"));

			Resource medication = VF.createIRI("urn:test:medication:1");
			connection.add(medication, RDF.TYPE, MEDICATION);
			connection.add(medication, CODE, VF.createLiteral("MED-1000"));

			connection.commit();
		}
	}

	private static void loadThemeData(SailRepository repository, Theme theme) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.READ_COMMITTED);
			ThemeDataSetGenerator.generate(theme, new RDFInserter(connection));
			connection.commit();
		}
	}

	private static long evaluateCount(SailRepository repository, String query) {
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
			assertTrue(result.hasNext(), "Aggregate count query should return one result row");
			BindingSet bindingSet = result.next();
			assertTrue(!result.hasNext(), "Aggregate count query should return only one result row");
			return ((Literal) bindingSet.getValue("count")).longValue();
		}
	}
}
